#include<bits/stdc++.h>
using namespace std;
int n,m;
int dfn[1000010],low[1000010],dfncnt,scccnt,id[1000010],siz[1000010];
int in[1000010],dp[1000010];
vector<int> mp[1000010],mp1[1000010];
bool instk[1000010],vis[1000010];
stack<int> s;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    int flag=0;
    for(int v:mp[x])
    {
        if(x==v)
        {
            flag=1;
        }
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        siz[scccnt]+=flag;
        do
        {
            top=s.top();
            instk[top]=0;
            siz[scccnt]++;
            id[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
    }
    for(int i=1;i<=n+1;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n+1;i++)
    {
        for(int j:mp[i])
        {
            if(id[i]!=id[j])
            {
                mp1[id[j]].push_back(id[i]);
                in[id[i]]++;
            }
        }
    }
    queue<int> q;
    for(int i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
        }
    }
    dp[id[n+1]]=1;
    if(siz[id[n+1]]>1)
    {
        dp[id[n+1]]=36500;
    }
    vis[id[n+1]]=1;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i:mp1[t])
        {
            in[i]--;
            if(in[i]==0)
            {
                q.push(i);
            }
            if(vis[t])
            {
                vis[i]=true;
            }
            dp[i]+=dp[t];
            if((vis[i]&&siz[i]>1)||dp[i]>36500)
            {
                dp[i]=36500;
            }
        }
    }
    int max1=0,cnt=0;
    for(int i=1;i<=n;i++)
    {
        int now=dp[id[i]];
        if(now>max1)
        {
            max1=now;
            cnt=1;
        }
        else if(now==max1)
        {
            cnt++;
        }
    }
    if(max1==36500)
    {
        printf("zawsze\n");
    }
    else
    {
        printf("%d\n",max1);
    }
    printf("%d\n",cnt);
    for(int i=1;i<=n;i++)
    {
        if(dp[id[i]]==max1)
        {
            printf("%d ",i);
        }
    }
    return 0;
}
